Index: src/pages/data-source/MinioUploadPage.tsx
===================================================================
--- src/pages/data-source/MinioUploadPage.tsx	
+++ src/pages/data-source/MinioUploadPage.tsx	
@@ -1,1561 +1,1564 @@
 import { useCallback, useEffect, useRef, useState } from 'react';
 import {
   CloudUpload,
   FileText,
   Image as ImageIcon,
   Video,
   Music,
   Box,
   X,
   CheckCircle2,
   AlertTriangle,
   Trash2,
   Eye,
   Loader2,
   Cloud,
   Database,
   Pause,
   Play,
   RotateCcw,
 } from 'lucide-react';
 import { PageContainer } from '@/layouts/PageContainer';
 import { Panel } from '@/components/common/Panel';
 import { Button } from '@/components/common/Button';
 import { minioService } from '@/services/minio.service';
 import type {
   FileCategory,
   FileUploadRecord,
   LocalUploadTask,
   ExternalObject,
   HdfsEntry,
   ImportTask,
 } from '@/types/minio';
 import { cn } from '@/utils/cn';
 import { toast } from 'sonner';
 import { getErrorMessage } from '@/utils/apiError';
 
 // ─── 分类规则（前端校验，与后端保持一致） ─────────────────────────
 
 const CATEGORY_LIMIT: Record<FileCategory, number> = {
   VIDEO: 1024 * 1024 * 1024,   // 1GB
   AUDIO: 100 * 1024 * 1024,
   IMAGE: 50 * 1024 * 1024,
   DOCUMENT: 50 * 1024 * 1024,
   UNCLASSIFIED: 100 * 1024 * 1024,
 };
 
 const CATEGORY_BUCKET: Record<FileCategory, string> = {
   VIDEO: 'videos',
   AUDIO: 'audios',
   IMAGE: 'pictures',
   DOCUMENT: 'documents',
   UNCLASSIFIED: 'unclassified',
 };
 
 const EXT_CATEGORY: Record<string, FileCategory> = {
   mp4: 'VIDEO', avi: 'VIDEO', mov: 'VIDEO', flv: 'VIDEO',
   wmv: 'VIDEO', rmvb: 'VIDEO', webm: 'VIDEO', mpga: 'VIDEO',
   mkv: 'VIDEO', m4v: 'VIDEO',
   wav: 'AUDIO', ogg: 'AUDIO', mp3: 'AUDIO', aac: 'AUDIO', m4a: 'AUDIO',
   flac: 'AUDIO', wma: 'AUDIO',
   png: 'IMAGE', jpg: 'IMAGE', jpeg: 'IMAGE', gif: 'IMAGE',
   svg: 'IMAGE', webp: 'IMAGE', bmp: 'IMAGE', tiff: 'IMAGE', ico: 'IMAGE',
   pdf: 'DOCUMENT', doc: 'DOCUMENT', docx: 'DOCUMENT',
   ppt: 'DOCUMENT', pptx: 'DOCUMENT', ofd: 'DOCUMENT',
   csv: 'DOCUMENT', xls: 'DOCUMENT', xlsx: 'DOCUMENT',
   wps: 'DOCUMENT', xml: 'DOCUMENT', html: 'DOCUMENT', htm: 'DOCUMENT',
   txt: 'DOCUMENT', md: 'DOCUMENT', json: 'DOCUMENT', log: 'DOCUMENT',
+  bin: 'DOCUMENT', dat: 'DOCUMENT', dump: 'DOCUMENT', img: 'DOCUMENT',
 };
 
 const CATEGORY_ICON: Record<FileCategory, typeof FileText> = {
   VIDEO: Video,
   AUDIO: Music,
   IMAGE: ImageIcon,
   DOCUMENT: FileText,
   UNCLASSIFIED: Box,
 };
 
 const BUCKET_OPTIONS = [
   { value: 'pictures', label: '🖼️ pictures' },
   { value: 'videos',   label: '📹 videos' },
   { value: 'audios',   label: '🎵 audios' },
   { value: 'documents',label: '📄 documents' },
 ];
 
 function getCategory(filename: string): FileCategory | null {
   const ext = filename.split('.').pop()?.toLowerCase() ?? '';
   return EXT_CATEGORY[ext] ?? null;
 }
 
 /** 浏览器选择框的 accept 属性：所有支持的扩展名列表（带 .） */
 const FILE_INPUT_ACCEPT = Object.keys(EXT_CATEGORY).map(e => '.' + e).join(',');
 
 function formatBytes(bytes: number): string {
   if (bytes < 1024) return `${bytes} B`;
   if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
   return `${(bytes / 1024 / 1024).toFixed(1)} MB`;
 }
 
 function formatSpeed(bytesPerSec: number): string {
   if (!bytesPerSec || bytesPerSec < 1024) return '0 KB/s';
   if (bytesPerSec < 1024 * 1024) return `${(bytesPerSec / 1024).toFixed(0)} KB/s`;
   return `${(bytesPerSec / 1024 / 1024).toFixed(1)} MB/s`;
 }
 
 function uuid(): string {
   return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
     const r = Math.random() * 16 | 0;
     return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
   });
 }
 
 /** 分片大小：5 MB，与后端 ChunkInitResponseDTO.chunkSize 严格保持一致；MinIO 要求 part ≥ 5MB */
 const CHUNK_SIZE = 5 * 1024 * 1024;
 /** 文件大小 < CHUNK_THRESHOLD 时走单流 init+upload；≥ 时走分片接口 */
 const CHUNK_THRESHOLD = CHUNK_SIZE;
 /** "恢复中"状态最小展示时长（毫秒），避免 init 极快时 UI 闪过 */
 const RESTORING_MIN_VISIBLE_MS = 800;
 
 // ─── 主页面 ───────────────────────────────────────────────────────
 
 export function MinioUploadPage() {
   // 父组件持有的 reload key：每次 UploadPanel 上传成功递增，
   // 触发 BrowsePanel 重新拉取记录列表（避免用户手动点刷新）
   const [browseReloadKey, setBrowseReloadKey] = useState(0);
   const triggerBrowseReload = useCallback(() => {
     setBrowseReloadKey((k) => k + 1);
   }, []);
   return (
     <PageContainer
       title="非结构化数据接入"
       description="支持本地文件上传与外部 S3 / MinIO / HDFS 数据源导入；文件按类型自动分发到对应 Bucket"
     >
       <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 h-full min-h-0">
         <UploadPanel onUploadSuccess={triggerBrowseReload} />
         <BrowsePanel reloadKey={browseReloadKey} />
       </div>
     </PageContainer>
   );
 }
 
 // ─── 上传面板 ─────────────────────────────────────────────────────
 
 function UploadPanel({ onUploadSuccess }: { onUploadSuccess?: () => void }) {
   const [queue, setQueue] = useState<LocalUploadTask[]>([]);
   const fileInputRef = useRef<HTMLInputElement>(null);
   const [dragOver, setDragOver] = useState(false);
   const [importMode, setImportMode] = useState<'local' | 'external' | 'hdfs'>('local');
   const [toast, setToast] = useState('');
 
   /** 持有最新 queue 引用，便于异步回调（如 uploadFileWithChunks 内部）读取暂停标记 */
   const queueRef = useRef<LocalUploadTask[]>([]);
   useEffect(() => {
     queueRef.current = queue;
   }, [queue]);
 
   // toast 3 秒后自动消失
   useEffect(() => {
     if (!toast) return;
     const t = window.setTimeout(() => setToast(''), 3000);
     return () => window.clearTimeout(t);
   }, [toast]);
 
   /**
    * 挂载时拉取后端尚未完成的上传记录（UPLOADING / PAUSED / FAILED），
    * 复原成"占位项"（NEEDS_FILE），让用户可以重新选择本地同名文件继续传分片
    * 设计权衡：浏览器刷新后原始 File 对象丢失，无法直接续传；必须用户重选
    */
   useEffect(() => {
     let cancelled = false;
     (async () => {
       try {
         // 并行拉取三种未完成状态
         const [uploadingPage, pausedPage, failedPage] = await Promise.all([
           minioService.listRecords({ size: 100, status: 'UPLOADING' }),
           minioService.listRecords({ size: 100, status: 'PAUSED' }),
           minioService.listRecords({ size: 100, status: 'FAILED' }),
         ]);
         if (cancelled) return;
         const records = [
           ...uploadingPage.content,
           ...pausedPage.content,
           ...failedPage.content,
         ];
         if (records.length === 0) return;
         const placeholders: LocalUploadTask[] = records.map((r) => {
           const category = (r.fileType as FileCategory) || getCategory(r.fileName) || 'UNCLASSIFIED';
           // 后端 JacksonConfig 把所有 Long 序列化成 String 以规避 JS Number 53 位精度限制；
           // 这里把 fileSize 显式转成 number，确保后续与 File.size（number）比较时类型一致
           const fileSizeNum = Number(r.fileSize ?? 0);
           const total = r.totalChunks ?? Math.ceil(fileSizeNum / CHUNK_SIZE);
           const done = r.uploadedChunks ?? 0;
           const uploadedSet = new Set<number>();
           for (let i = 1; i <= done; i++) uploadedSet.add(i);
           return {
             fileId: r.fileId,
             file: null,
             category,
             bucket: r.bucket ?? CATEGORY_BUCKET[category],
             limit: CATEGORY_LIMIT[category],
             status: 'NEEDS_FILE' as const,
             progress: fileSizeNum > 0
               ? Math.min(100, Math.round((done * CHUNK_SIZE) / fileSizeNum * 100))
               : 0,
             uploadId: undefined, // 续传时 chunks/init 会重新返回最新 uploadId
             uploadedParts: uploadedSet,
             totalChunks: total,
             expectedFileName: r.fileName,
             expectedFileSize: fileSizeNum,
             expectedMimeType: r.mimeType,
           };
         });
         // 合并：避免与队列里已存在的同 fileId 重复
         setQueue((prev) => {
           const existingIds = new Set(prev.map((p) => p.fileId));
           const fresh = placeholders.filter((p) => !existingIds.has(p.fileId));
           return [...fresh, ...prev];
         });
       } catch {
         /* 静默：拉取失败不影响新建上传 */
       }
     })();
     return () => { cancelled = true; };
   }, []);
 
   const handleAddFiles = useCallback((files: FileList | File[]) => {
     const newTasks: LocalUploadTask[] = [];
     let unsupportedCount = 0;
     for (const file of Array.from(files)) {
       const category = getCategory(file.name);
       if (!category) {
         unsupportedCount++;
       } else {
         newTasks.push({
           fileId: uuid(), file, category,
           bucket: CATEGORY_BUCKET[category],
           limit: CATEGORY_LIMIT[category],
           status: 'PENDING', progress: 0,
           uploadedParts: new Set<number>(),
           totalChunks: Math.ceil(file.size / CHUNK_SIZE),
         });
       }
     }
     if (unsupportedCount > 0) {
       setToast('不支持发送该类型文件');
     }
     if (newTasks.length === 0) return;
     setQueue(prev => {
       // 过滤掉已在队列中的同名同大小文件（占位项也按 expectedFileName/Size 比对，避免重复显示）
       const filtered = newTasks.filter(t => !prev.some(p => {
         const pName = p.file?.name ?? p.expectedFileName;
         const pSize = p.file?.size ?? p.expectedFileSize;
         const tName = t.file?.name ?? t.expectedFileName;
         const tSize = t.file?.size ?? t.expectedFileSize;
         return pName === tName && pSize === tSize;
       }));
       return [...prev, ...filtered];
     });
   }, []);
 
   const handleRemove = useCallback((idx: number) => {
     const target = queueRef.current[idx];
     setQueue((prev) => prev.filter((_, i) => i !== idx));
     // NEEDS_FILE 占位项被用户主动移除：通知后端取消，避免下次刷新再次出现
     if (target && target.status === 'NEEDS_FILE') {
       void minioService.notifyCancel(target.fileId).catch(() => { /* 静默：占位项可能已不存在 */ });
     }
   }, []);
 
   /** 在 queueRef 中查找最新任务状态（用于异步循环中读取暂停/取消标记） */
   function getLatest(fileId: string): LocalUploadTask | undefined {
     return queueRef.current.find((t) => t.fileId === fileId);
   }
 
   /** 局部更新任务状态 */
   function patchTask(fileId: string, patch: Partial<LocalUploadTask>) {
     setQueue((prev) =>
       prev.map((t) => (t.fileId === fileId ? { ...t, ...patch } : t)),
     );
   }
 
   /**
    * 分片上传：
    * 1. 调用 /chunks/init 获取 uploadId 与已上传分片号
    * 2. 逐片上传未完成分片，每片完成后更新进度
    * 3. 全部上传成功调用 /chunks/complete 触发合并
    * 4. 任意环节检查 paused/cancelled 标记以中断
    */
   async function uploadFileWithChunks(t: LocalUploadTask) {
     const file = t.file;
     if (!file) {
       // 占位项必须先重选文件，由 handlePickFileForResume 触发本函数时 file 一定已挂载
       patchTask(t.fileId, { status: 'NEEDS_FILE' });
       return;
     }
     const totalChunks = Math.ceil(file.size / CHUNK_SIZE);
 
     // 是否为恢复场景：此前传过分片
     const isResuming = !!t.uploadId && (t.uploadedParts?.size ?? 0) > 0;
     const restoreStartTs = Date.now();
 
     if (isResuming) {
       patchTask(t.fileId, { status: 'RESTORING' });
     } else {
       patchTask(t.fileId, { status: 'UPLOADING', progress: 0 });
     }
 
     // ── Step 1: 初始化（后端三层查找：内存→DB→新建） ──
     let initResp;
     try {
       initResp = await minioService.initChunked({
         fileId: t.fileId,
         fileName: file.name,
         fileSize: file.size,
         mimeType: file.type || 'application/octet-stream',
         totalChunks,
       });
     } catch (e) {
       patchTask(t.fileId, {
         status: 'ERROR',
         reason: '初始化失败：' + getErrorMessage(e, ''),
       });
       return;
     }
 
     const uploadedSet = new Set<number>(initResp.uploadedChunks ?? []);
     let uploadedBytes = uploadedSet.size * CHUNK_SIZE;
     if (uploadedBytes > file.size) uploadedBytes = file.size;
 
     patchTask(t.fileId, {
       uploadId: initResp.uploadId,
       uploadedParts: uploadedSet,
       totalChunks: initResp.totalChunks,
       progress: file.size > 0 ? Math.min(100, Math.round((uploadedBytes / file.size) * 100)) : 0,
     });
 
     // 恢复场景：保证 RESTORING 至少展示 800ms
     if (isResuming) {
       const elapsed = Date.now() - restoreStartTs;
       if (elapsed < RESTORING_MIN_VISIBLE_MS) {
         await sleep(RESTORING_MIN_VISIBLE_MS - elapsed);
       }
     }
     patchTask(t.fileId, { status: 'UPLOADING' });
 
     // ── Step 2: 逐片上传 ──
     const startTime = Date.now();
 
     for (let partNum = 1; partNum <= totalChunks; partNum++) {
       // 暂停/取消检查（从 queueRef 读取最新标记）
       const latest = getLatest(t.fileId);
       if (latest?.cancelled) {
         patchTask(t.fileId, { status: 'CANCELLED', xhr: null });
         try { await minioService.notifyCancel(t.fileId); } catch { /* ignore */ }
         return;
       }
       if (latest?.paused) {
         patchTask(t.fileId, { status: 'PAUSED', xhr: null });
         try { await minioService.notifyPause(t.fileId); } catch { /* ignore */ }
         return;
       }
       if (uploadedSet.has(partNum)) continue;
 
       const start = (partNum - 1) * CHUNK_SIZE;
       const end = Math.min(start + CHUNK_SIZE, file.size);
       const blob = file.slice(start, end);
 
       const { xhr, promise } = minioService.uploadChunk(t.fileId, partNum, blob, file.name);
       patchTask(t.fileId, { xhr });
 
       try {
         const chunkResp = await promise;
         if (!chunkResp.skipped) {
           uploadedBytes += end - start;
         }
         uploadedSet.add(partNum);
         const progress = file.size > 0
           ? Math.min(100, Math.round((uploadedBytes / file.size) * 100))
           : 0;
         const elapsedSec = (Date.now() - startTime) / 1000;
         const speed = elapsedSec > 0 ? uploadedBytes / elapsedSec : 0;
         patchTask(t.fileId, {
           uploadedParts: new Set(uploadedSet),
           progress,
           speed,
           xhr: null,
         });
       } catch (e: unknown) {
         // abort 由暂停/取消触发：循环顶部检查会捕获并设置正确状态
         if (e instanceof DOMException && e.name === 'AbortError') {
           // 让下一轮循环去判断 paused/cancelled 标记
           continue;
         }
         patchTask(t.fileId, {
           status: 'ERROR',
           reason: '分片 ' + partNum + ' 上传失败：' + getErrorMessage(e, ''),
           xhr: null,
         });
         return;
       }
     }
 
     // ── Step 3: 合并 ──
     try {
       const completeResp = await minioService.completeChunked(t.fileId);
       patchTask(t.fileId, {
         status: 'OK',
         progress: 100,
         url: completeResp.url,
         xhr: null,
       });
       // 通知父组件刷新文件浏览列表（reloadKey 递增触发 BrowsePanel.useEffect）
       onUploadSuccess?.();
     } catch (e) {
       patchTask(t.fileId, {
         status: 'ERROR',
         reason: '合并失败：' + getErrorMessage(e, ''),
         xhr: null,
       });
     }
   }
 
   /** 单流上传（小文件 < 5MB） */
   async function uploadFileSingle(t: LocalUploadTask) {
     const file = t.file;
     if (!file) {
       patchTask(t.fileId, { status: 'NEEDS_FILE' });
       return;
     }
     patchTask(t.fileId, { status: 'UPLOADING', progress: 0 });
     try {
       await minioService.init({
         fileId: t.fileId,
         fileName: file.name,
         fileSize: file.size,
         mimeType: file.type || 'application/octet-stream',
       });
       await minioService.upload(t.fileId, file);
       const rec = await minioService.progress(t.fileId);
       if (rec.uploadStatus === 'SUCCESS') {
         patchTask(t.fileId, { status: 'OK', progress: 100, url: rec.url });
         // 通知父组件刷新文件浏览列表
         onUploadSuccess?.();
       } else {
         patchTask(t.fileId, {
           status: 'ERROR',
           reason: rec.errorMessage ?? '上传失败',
         });
       }
     } catch (e) {
       patchTask(t.fileId, {
         status: 'ERROR',
         reason: getErrorMessage(e, '上传失败'),
       });
     }
   }
 
   /** 上传调度：按文件大小自动选择策略 */
   async function doUpload(targets: LocalUploadTask[]) {
     for (const t of targets) {
       // 占位项不应进入此分支；防御性检查
       if (!t.file) continue;
       if (t.file.size >= CHUNK_THRESHOLD) {
         await uploadFileWithChunks(t);
       } else {
         await uploadFileSingle(t);
       }
     }
   }
 
   const handleUploadAll = useCallback(async () => {
     // PENDING 任务一定来自 handleAddFiles，file 必非空（占位项是 NEEDS_FILE 状态，不会被选中）
     const targets = queue.filter((t) => t.status === 'PENDING' && t.file != null && t.file.size <= t.limit);
     if (targets.length === 0) return;
 
     // 先把超限的标记为 REJECTED
     setQueue((prev) =>
       prev.map((t) =>
         t.status === 'PENDING' && t.file != null && t.file.size > t.limit
           ? { ...t, status: 'REJECTED', reason: `超过 ${Math.round(t.limit / 1024 / 1024)}MB 限制` }
           : t,
       ),
     );
 
     // 冲突检测
     const conflictNames = new Set<string>();
     for (const t of targets) {
       if (!t.file) continue;
       const objectKey = `${t.category.toLowerCase()}/${t.fileId}/${t.file.name}`;
       try {
         const exists = await minioService.checkConflict(t.bucket, objectKey);
         if (exists) conflictNames.add(t.fileId);
       } catch { /* ignore */ }
     }
     if (conflictNames.size > 0) {
       setQueue((prev) =>
         prev.map((t) => (conflictNames.has(t.fileId) ? { ...t, status: 'CONFLICT' } : t)),
       );
       return; // 等用户确认
     }
 
     await doUpload(targets);
   }, [queue]);
 
   const handleResolveConflict = useCallback(
     async (fileId: string, action: 'replace' | 'skip') => {
       if (action === 'skip') {
         setQueue((prev) => prev.filter((x) => x.fileId !== fileId));
         return;
       }
       const target = queue.find((x) => x.fileId === fileId);
       if (!target) return;
       // 替换 = 重新生成 fileId 避免与已存在的冲突，然后上传
       const newId = uuid();
       const replaced: LocalUploadTask = {
         ...target,
         fileId: newId,
         status: 'PENDING',
         uploadedParts: new Set<number>(),
       };
       setQueue((prev) => prev.map((x) => (x.fileId === fileId ? replaced : x)));
       await doUpload([replaced]);
     },
     [queue],
   );
 
   /** 暂停：标记 paused，abort 在途 XHR；后端通知由循环捕获后调用 */
   const handlePause = useCallback((fileId: string) => {
     const t = queueRef.current.find((x) => x.fileId === fileId);
     if (!t) return;
     patchTask(fileId, { paused: true });
     if (t.xhr) {
       try { t.xhr.abort(); } catch { /* ignore */ }
     }
   }, []);
 
   /** 恢复：通知后端，重新进入 uploadFileWithChunks 流程（init 会自动跳过已上传分片） */
   const handleResume = useCallback(async (fileId: string) => {
     const t = queueRef.current.find((x) => x.fileId === fileId);
     if (!t) return;
     patchTask(fileId, { paused: false, status: 'RESTORING' });
     try { await minioService.notifyResume(fileId); } catch { /* ignore */ }
     await uploadFileWithChunks({ ...t, paused: false });
   // eslint-disable-next-line react-hooks/exhaustive-deps
   }, []);
 
   /** 取消：标记 cancelled + abort 在途 + 通知后端 */
   const handleCancel = useCallback(async (fileId: string) => {
     const t = queueRef.current.find((x) => x.fileId === fileId);
     if (!t) return;
     patchTask(fileId, { cancelled: true });
     if (t.xhr) {
       try { t.xhr.abort(); } catch { /* ignore */ }
     }
     try { await minioService.notifyCancel(fileId); } catch { /* ignore */ }
     patchTask(fileId, { status: 'CANCELLED' });
   }, []);
 
   /** 重试失败任务：重置状态后重新上传 */
   const handleRetry = useCallback(async (fileId: string) => {
     const t = queueRef.current.find((x) => x.fileId === fileId);
     if (!t || !t.file) return;
     // 重新生成 fileId 避免与失败的旧记录冲突
     const newId = uuid();
     const reset: LocalUploadTask = {
       ...t,
       fileId: newId,
       status: 'PENDING',
       progress: 0,
       reason: undefined,
       uploadId: undefined,
       uploadedParts: new Set<number>(),
       paused: false,
       cancelled: false,
       xhr: null,
     };
     setQueue((prev) => prev.map((x) => (x.fileId === fileId ? reset : x)));
     await doUpload([reset]);
   // eslint-disable-next-line react-hooks/exhaustive-deps
   }, []);
 
   /**
    * NEEDS_FILE 占位项的"重新选择文件"流程：
    * 1. 校验用户选的 File 与后端记录的 fileName + fileSize 一致
    * 2. 不一致：弹 toast 提示，不动队列
    * 3. 一致：把 file 写回任务，调 uploadFileWithChunks（init 会自动恢复 uploadedChunks）
    */
   const handlePickFileForResume = useCallback(
     async (fileId: string, file: File) => {
       const t = queueRef.current.find((x) => x.fileId === fileId);
       if (!t) return;
       if (t.expectedFileName !== file.name) {
         setToast(`文件名不匹配：需要 ${t.expectedFileName}`);
         return;
       }
       // 防御性 Number 转换：expectedFileSize 在后端 Long->String 序列化下有可能漏转
       const expected = Number(t.expectedFileSize ?? 0);
       if (expected !== file.size) {
         setToast(`文件大小不匹配：需要 ${formatBytes(expected)}（实际 ${formatBytes(file.size)}）`);
         return;
       }
       // 写回 file，状态切到 RESTORING；uploadFileWithChunks 会通过 chunks/init
       // 从后端拿到 resumed=true、uploadedChunks=[...] 然后跳过已传分片
       const restored: LocalUploadTask = {
         ...t,
         file,
         status: 'RESTORING',
         paused: false,
         cancelled: false,
       };
       setQueue((prev) => prev.map((x) => (x.fileId === fileId ? restored : x)));
       try { await minioService.notifyResume(fileId); } catch { /* ignore */ }
       await uploadFileWithChunks(restored);
     },
   // eslint-disable-next-line react-hooks/exhaustive-deps
     [],
   );
 
   return (
     <Panel
       title={
         <span className="flex items-center gap-2">
           <CloudUpload className="w-4 h-4 text-accent" />
           文件上传
         </span>
       }
       subtitle="支持拖拽多文件，按扩展名自动路由到对应 Bucket"
       noPadding
     >
       <div className="p-4 flex flex-col gap-4 h-full overflow-auto">
         {/* 不支持类型提示 */}
         {toast && (
           <div className="fixed top-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-2 px-4 py-2.5 rounded-md border border-status-warn/40 bg-status-warn/10 text-status-warn text-2xs font-mono shadow-lg backdrop-blur-sm max-w-sm">
             <AlertTriangle className="w-3.5 h-3.5 shrink-0" />
             {toast}
           </div>
         )}
 
         {/* 切换：本地 / 外部 S3 / HDFS */}
         <div className="flex gap-1">
           <TabButton active={importMode === 'local'} onClick={() => setImportMode('local')}>
             <CloudUpload className="w-3 h-3" />
             本地上传
           </TabButton>
           <TabButton active={importMode === 'external'} onClick={() => setImportMode('external')}>
             <Cloud className="w-3 h-3" />
             外部 S3 / MinIO
           </TabButton>
           <TabButton active={importMode === 'hdfs'} onClick={() => setImportMode('hdfs')}>
             <Database className="w-3 h-3" />
             HDFS
           </TabButton>
         </div>
 
         {importMode === 'local' && (
           <>
             {/* 支持类型说明卡片 */}
             <div className="border-0.5 border-line rounded-sm bg-bg-subtle/40 divide-y-0.5 divide-line">
               <div className="px-3 py-2 text-2xs font-mono uppercase tracking-wider text-text-dim flex items-center gap-1.5">
                 <FileText className="w-3 h-3 text-accent" />
                 仅支持以下格式，其他格式不支持上传
               </div>
               <SupportRow
                 icon={<Video className="w-3.5 h-3.5 text-accent" />}
                 label="视频"
                 limit="≤ 1 GB"
                 exts="mp4 avi mov flv wmv rmvb webm mpga mkv m4v"
               />
               <SupportRow
                 icon={<Music className="w-3.5 h-3.5 text-accent" />}
                 label="音频"
                 limit="≤ 100 MB"
                 exts="wav ogg mp3 aac m4a flac wma"
               />
               <SupportRow
                 icon={<ImageIcon className="w-3.5 h-3.5 text-accent" />}
                 label="图片"
                 limit="≤ 50 MB"
                 exts="png jpg jpeg gif svg webp bmp tiff ico"
               />
               <SupportRow
                 icon={<FileText className="w-3.5 h-3.5 text-accent" />}
                 label="文档"
                 limit="≤ 50 MB"
                 exts="pdf doc docx ppt pptx ofd csv xls xlsx wps xml html htm txt md json log"
               />
             </div>
 
             {/* 拖拽区 */}
             <div
               onDragOver={(e) => {
                 e.preventDefault();
                 setDragOver(true);
               }}
               onDragLeave={() => setDragOver(false)}
               onDrop={(e) => {
                 e.preventDefault();
                 setDragOver(false);
                 if (e.dataTransfer.files.length > 0) handleAddFiles(e.dataTransfer.files);
               }}
               onClick={() => fileInputRef.current?.click()}
               className={cn(
                 'border-0.5 border-dashed rounded-sm py-8 px-4 flex flex-col items-center gap-2 cursor-pointer transition-colors text-center',
                 dragOver
                   ? 'border-accent bg-accent/10'
                   : 'border-line hover:border-accent/40 hover:bg-accent/5',
               )}
             >
               <CloudUpload className="w-8 h-8 text-accent/60" />
               <div className="text-xs text-text-muted">点击或拖拽文件到此处</div>
               <input
                 ref={fileInputRef}
                 type="file"
                 multiple
                 hidden
                 onChange={(e) => {
                   if (e.target.files) handleAddFiles(e.target.files);
                   e.target.value = '';
                 }}
               />
             </div>
 
             {/* 队列 */}
             {queue.length > 0 && (
               <div className="flex flex-col gap-2">
                 <div className="flex items-center justify-between">
                   <div className="text-2xs font-mono uppercase tracking-wider text-text-dim">
                     待上传 {queue.length} 个文件
                   </div>
                   <Button variant="primary" onClick={handleUploadAll}>
                     全部上传
                   </Button>
                 </div>
                 <div className="space-y-1.5">
                   {queue.map((t, i) => (
                     <QueueItem
                       key={t.fileId}
                       task={t}
                       index={i}
                       onRemove={() => handleRemove(i)}
                       onResolveConflict={handleResolveConflict}
                       onPause={handlePause}
                       onResume={handleResume}
                       onCancel={handleCancel}
                       onRetry={handleRetry}
                       onPickFileForResume={handlePickFileForResume}
                     />
                   ))}
                 </div>
               </div>
             )}
           </>
         )}
 
         {importMode === 'external' && <ExternalImportSection />}
         {importMode === 'hdfs' && <HdfsImportSection />}
       </div>
     </Panel>
   );
 }
 
 function SupportRow({
   icon, label, limit, exts,
 }: {
   icon: React.ReactNode;
   label: string;
   limit: string;
   exts: string;
 }) {
   return (
     <div className="px-3 py-2 flex items-center gap-2.5 text-2xs">
       <span className="shrink-0">{icon}</span>
       <span className="font-medium text-text w-10 shrink-0">{label}</span>
       <span className="font-mono text-text-dim shrink-0">{limit}</span>
       <span className="font-mono text-text-muted truncate" title={exts}>{exts}</span>
     </div>
   );
 }
 
 function TabButton({
   active,
   onClick,
   children,
 }: {
   active: boolean;
   onClick: () => void;
   children: React.ReactNode;
 }) {
   return (
     <button
       onClick={onClick}
       className={cn(
         'flex items-center gap-1 px-3 py-1.5 text-xs font-mono uppercase tracking-wider rounded-sm border-0.5 transition-colors',
         active
           ? 'bg-accent/10 text-accent border-accent/40'
           : 'bg-transparent text-text-muted border-line hover:text-text hover:bg-surface-hover',
       )}
     >
       {children}
     </button>
   );
 }
 
 function QueueItem({
   task,
   index: _index,
   onRemove,
   onResolveConflict,
   onPause,
   onResume,
   onCancel,
   onRetry,
   onPickFileForResume,
 }: {
   task: LocalUploadTask;
   index: number;
   onRemove: () => void;
   onResolveConflict: (fileId: string, action: 'replace' | 'skip') => void;
   onPause: (fileId: string) => void;
   onResume: (fileId: string) => void;
   onCancel: (fileId: string) => void;
   onRetry: (fileId: string) => void;
   onPickFileForResume: (fileId: string, file: File) => void;
 }) {
   const Icon = CATEGORY_ICON[task.category];
   /** 占位项无 file，用 expectedFileName/expectedFileSize 兜底 */
   const displayName = task.file?.name ?? task.expectedFileName ?? '(未知文件名)';
   const displaySize = task.file?.size ?? task.expectedFileSize ?? 0;
   const isChunked = displaySize >= CHUNK_THRESHOLD;
   /** NEEDS_FILE 状态下，"重新选择文件"按钮的隐藏 input ref */
   const resumeInputRef = useRef<HTMLInputElement>(null);
   return (
     <div className="border-0.5 border-line rounded-sm p-2.5 flex items-center gap-2.5 bg-bg-subtle/40">
       <Icon className="w-3.5 h-3.5 text-accent shrink-0" />
       <div className="flex-1 min-w-0">
         <div className="text-2xs text-text font-mono truncate" title={displayName}>
           {displayName}
         </div>
         <div className="text-2xs text-text-dim mt-0.5 flex items-center gap-2">
           <span>{formatBytes(displaySize)}</span>
           {task.limit > 0 && (
             <>
               <span>·</span>
               <span>限制 {Math.round(task.limit / 1024 / 1024)}MB</span>
             </>
           )}
           {(task.status === 'UPLOADING' || task.status === 'PAUSED') && (task.speed ?? 0) > 0 && (
             <>
               <span>·</span>
               <span>{formatSpeed(task.speed ?? 0)}</span>
             </>
           )}
         </div>
         {(task.status === 'UPLOADING' || task.status === 'PAUSED' || task.status === 'RESTORING') && (
           <div className="mt-1.5 h-1 bg-line rounded-full overflow-hidden">
             <div
               className={cn(
                 'h-full transition-all duration-300',
                 task.status === 'PAUSED' ? 'bg-status-warn' : 'bg-accent',
               )}
               style={{ width: `${task.progress}%` }}
             />
           </div>
         )}
         {task.status === 'OK' && (
           <div className="mt-1 h-1 bg-line rounded-full overflow-hidden">
             <div className="h-full bg-status-ok" style={{ width: '100%' }} />
           </div>
         )}
         {task.status === 'CONFLICT' && (
           <div className="mt-1.5 flex items-center gap-2">
             <span className="text-2xs text-status-warn flex items-center gap-1">
               <AlertTriangle className="w-3 h-3" />
               文件已存在
             </span>
             <button
               onClick={() => onResolveConflict(task.fileId, 'replace')}
               className="text-2xs text-accent hover:underline"
             >
               替换
             </button>
             <button
               onClick={() => onResolveConflict(task.fileId, 'skip')}
               className="text-2xs text-status-danger hover:underline"
             >
               跳过
             </button>
           </div>
         )}
         {task.status === 'OK' && (
           <div className="text-2xs text-status-ok mt-0.5 flex items-center gap-1">
             <CheckCircle2 className="w-3 h-3" /> 上传完成
           </div>
         )}
         {task.status === 'RESTORING' && (
           <div className="text-2xs text-accent mt-0.5 flex items-center gap-1">
             <Loader2 className="w-3 h-3 animate-spin" /> 正在恢复上传
           </div>
         )}
         {task.status === 'PAUSED' && (
           <div className="text-2xs text-status-warn mt-0.5 flex items-center gap-1">
             <Pause className="w-3 h-3" /> 已暂停 · {task.progress}%
           </div>
         )}
         {task.status === 'ERROR' && (
           <div className="text-2xs text-status-danger mt-0.5 flex items-center gap-1">
             <X className="w-3 h-3" /> {task.reason ?? '失败'}
           </div>
         )}
         {task.status === 'CANCELLED' && (
           <div className="text-2xs text-text-dim mt-0.5 flex items-center gap-1">
             <X className="w-3 h-3" /> 已取消
           </div>
         )}
         {task.status === 'REJECTED' && (
           <div className="text-2xs text-status-warn mt-0.5">{task.reason}</div>
         )}
         {task.status === 'NEEDS_FILE' && (
           <>
             <div className="mt-1 h-1 bg-line rounded-full overflow-hidden">
               <div
                 className="h-full bg-status-warn/60"
                 style={{ width: `${task.progress}%` }}
               />
             </div>
             <div className="text-2xs text-status-warn mt-1 flex items-center gap-1">
               <AlertTriangle className="w-3 h-3" />
               页面刷新后未完成 · 已传 {task.progress}% · 请重新选择本地同名文件继续
             </div>
           </>
         )}
       </div>
 
       {/* 操作按钮区 */}
       {task.status === 'PENDING' && (
         <button
           onClick={onRemove}
           className="text-text-dim hover:text-status-danger transition-colors"
           title="移除"
         >
           <X className="w-3.5 h-3.5" />
         </button>
       )}
       {task.status === 'UPLOADING' && (
         <>
           {isChunked && (
             <button
               onClick={() => onPause(task.fileId)}
               className="text-text-dim hover:text-status-warn transition-colors"
               title="暂停"
             >
               <Pause className="w-3.5 h-3.5" />
             </button>
           )}
           <button
             onClick={() => onCancel(task.fileId)}
             className="text-text-dim hover:text-status-danger transition-colors"
             title="取消"
           >
             <X className="w-3.5 h-3.5" />
           </button>
           <Loader2 className="w-3.5 h-3.5 text-accent animate-spin" />
         </>
       )}
       {task.status === 'PAUSED' && (
         <>
           <button
             onClick={() => onResume(task.fileId)}
             className="text-accent hover:text-accent-hover transition-colors"
             title="恢复"
           >
             <Play className="w-3.5 h-3.5" />
           </button>
           <button
             onClick={() => onCancel(task.fileId)}
             className="text-text-dim hover:text-status-danger transition-colors"
             title="取消"
           >
             <X className="w-3.5 h-3.5" />
           </button>
         </>
       )}
       {task.status === 'RESTORING' && (
         <Loader2 className="w-3.5 h-3.5 text-accent animate-spin" />
       )}
       {(task.status === 'ERROR' || task.status === 'CANCELLED') && (
         <>
           <button
             onClick={() => onRetry(task.fileId)}
             className="text-accent hover:text-accent-hover transition-colors"
             title="重试"
           >
             <RotateCcw className="w-3.5 h-3.5" />
           </button>
           <button
             onClick={onRemove}
             className="text-text-dim hover:text-status-danger transition-colors"
             title="移除"
           >
             <X className="w-3.5 h-3.5" />
           </button>
         </>
       )}
       {task.status === 'NEEDS_FILE' && (
         <>
           <button
             onClick={() => resumeInputRef.current?.click()}
             className="text-accent hover:text-accent-hover transition-colors flex items-center gap-1 text-2xs"
             title={`重新选择 ${task.expectedFileName}`}
           >
             <CloudUpload className="w-3.5 h-3.5" />
             重新选择
           </button>
           <input
             ref={resumeInputRef}
             type="file"
             hidden
             onChange={(e) => {
               const f = e.target.files?.[0];
               if (f) onPickFileForResume(task.fileId, f);
               e.target.value = '';
             }}
           />
           <button
             onClick={onRemove}
             className="text-text-dim hover:text-status-danger transition-colors"
             title="移除"
           >
             <X className="w-3.5 h-3.5" />
           </button>
         </>
       )}
     </div>
   );
 }
 
 // ─── 外部 S3/MinIO 导入 ───────────────────────────────────────────
 
 function ExternalImportSection() {
   const [endpoint, setEndpoint] = useState('');
   const [accessKey, setAccessKey] = useState('');
   const [secretKey, setSecretKey] = useState('');
   const [bucket, setBucket] = useState('');
   const [prefix, setPrefix] = useState('');
   const [loading, setLoading] = useState(false);
   const [entries, setEntries] = useState<ExternalObject[] | null>(null);
   const [checked, setChecked] = useState<Set<string>>(new Set());
   const [task, setTask] = useState<ImportTask | null>(null);
 
   const handleBrowse = async () => {
     if (!endpoint || !accessKey || !secretKey || !bucket) {
       toast.error('请填写 IP地址:端口 / 用户名 / 密码 / Bucket');
       return;
     }
     setLoading(true);
     setEntries(null);
     setChecked(new Set());
     try {
       const list = await minioService.listExternal({
         endpoint,
         accessKey,
         secretKey,
         bucket,
         prefix,
         pathStyle: true,
       });
       setEntries(list);
     } catch (e) {
       toast.error(getErrorMessage(e, '连接外部源失败'));
     } finally {
       setLoading(false);
     }
   };
 
   const handleNavigate = (newPrefix: string) => {
     setPrefix(newPrefix);
     setTimeout(handleBrowse, 0);
   };
 
   const handleImport = async () => {
     if (checked.size === 0) return;
     try {
       const started = await minioService.copyExternal({
         endpoint, accessKey, secretKey, bucket, prefix, pathStyle: true,
         keys: Array.from(checked),
       });
       setTask(started);
       pollTask(started.taskId, minioService.externalProgress, setTask, () => {
         setChecked(new Set());
+        setTask(null);
         handleBrowse();
       });
     } catch (e) {
       toast.error(getErrorMessage(e, '启动导入失败'));
     }
   };
 
   return (
     <div className="flex flex-col gap-3">
       <div className="grid grid-cols-1 gap-2">
         <Field label="IP地址:端口" value={endpoint} onChange={setEndpoint} placeholder="请输入 IP 地址和端口，如：http://10.0.0.5:9000" />
         <div className="grid grid-cols-2 gap-2">
           <Field label="用户名" value={accessKey} onChange={setAccessKey} placeholder="请输入用户名，如：minioadmin" />
           <Field label="密码" value={secretKey} onChange={setSecretKey} placeholder="请输入密码" type="password" />
         </div>
         <div className="grid grid-cols-[1fr_auto] gap-2 items-end">
           <Field label="Bucket" value={bucket} onChange={setBucket} placeholder="请输入 Bucket 名称，如：my-bucket" />
           <Button variant="primary" onClick={handleBrowse} disabled={loading}>
             {loading ? <Loader2 className="w-3 h-3 animate-spin" /> : '连接并浏览'}
           </Button>
         </div>
       </div>
 
       {entries && (
         <div className="border-0.5 border-line rounded-sm p-2 bg-bg-subtle/40">
           <div className="flex items-center justify-between mb-2">
             <Breadcrumb prefix={prefix} bucket={bucket} onNavigate={handleNavigate} />
             <Button
               variant="primary"
               onClick={handleImport}
               disabled={checked.size === 0 || !!task && task.status === 'RUNNING'}
             >
               导入所选 ({checked.size})
             </Button>
           </div>
           {task ? (
             <ImportProgressBar task={task} />
           ) : (
             <EntryList
               entries={entries}
               checked={checked}
               onToggle={(k, on) => {
                 setChecked((prev) => {
                   const next = new Set(prev);
                   if (on) next.add(k); else next.delete(k);
                   return next;
                 });
               }}
               onNavigate={handleNavigate}
             />
           )}
         </div>
       )}
     </div>
   );
 }
 
 // ─── HDFS 导入 ────────────────────────────────────────────────────
 
 function HdfsImportSection() {
   const [namenode, setNamenode] = useState('');
   const [user, setUser] = useState('hdfs');
   const [password, setPassword] = useState('');
   const [path, setPath] = useState('/');
   const [loading, setLoading] = useState(false);
   const [entries, setEntries] = useState<HdfsEntry[] | null>(null);
   const [checked, setChecked] = useState<Set<string>>(new Set());
   const [task, setTask] = useState<ImportTask | null>(null);
 
   const handleBrowse = async (newPath?: string) => {
     if (!namenode) {
       toast.error('请填写 IP地址');
       return;
     }
     const p = newPath ?? path;
     setPath(p);
     setLoading(true);
     setEntries(null);
     setChecked(new Set());
     try {
       const list = await minioService.listHdfs({
         namenode, user, password, path: p,
       });
       setEntries(list);
     } catch (e) {
       toast.error(getErrorMessage(e, '连接 HDFS 失败'));
     } finally {
       setLoading(false);
     }
   };
 
   const handleImport = async () => {
     if (checked.size === 0) return;
     try {
       const started = await minioService.copyHdfs({
         namenode, user, password, path,
         keys: Array.from(checked),
       });
       setTask(started);
       pollTask(started.taskId, minioService.hdfsProgress, setTask, () => {
         setChecked(new Set());
+        setTask(null);
         handleBrowse(path);
       });
     } catch (e) {
       toast.error(getErrorMessage(e, '启动导入失败'));
     }
   };
 
   return (
     <div className="flex flex-col gap-3">
       <div className="grid grid-cols-1 gap-2">
         <Field label="IP地址" value={namenode} onChange={setNamenode} placeholder="请输入 IP 地址，如：http://10.0.0.10:9870" />
         <div className="grid grid-cols-2 gap-2">
           <Field label="用户名" value={user} onChange={setUser} placeholder="请输入用户名，如：hdfs" />
           <Field label="密码" value={password} onChange={setPassword} placeholder="可选" type="password" />
         </div>
         <div className="grid grid-cols-[1fr_auto] gap-2 items-end">
           <Field label="路径" value={path} onChange={setPath} placeholder="/" />
           <Button variant="primary" onClick={() => handleBrowse()} disabled={loading}>
             {loading ? <Loader2 className="w-3 h-3 animate-spin" /> : '连接并浏览'}
           </Button>
         </div>
       </div>
 
       {entries && (
         <div className="border-0.5 border-line rounded-sm p-2 bg-bg-subtle/40">
           <div className="flex items-center justify-between mb-2">
             <div className="text-2xs font-mono text-text-muted">hdfs://{path}</div>
             <Button
               variant="primary"
               onClick={handleImport}
               disabled={checked.size === 0 || !!task && task.status === 'RUNNING'}
             >
               导入所选 ({checked.size})
             </Button>
           </div>
           {task ? (
             <ImportProgressBar task={task} />
           ) : (
             <HdfsEntryList
               entries={entries}
               checked={checked}
               onToggle={(k, on) => {
                 setChecked((prev) => {
                   const next = new Set(prev);
                   if (on) next.add(k); else next.delete(k);
                   return next;
                 });
               }}
               onNavigate={(name) => handleBrowse((path.endsWith('/') ? path : path + '/') + name)}
             />
           )}
         </div>
       )}
     </div>
   );
 }
 
 // ─── 公共子组件 ───────────────────────────────────────────────────
 
 function Field({
   label, value, onChange, placeholder, type = 'text',
 }: {
   label: string;
   value: string;
   onChange: (v: string) => void;
   placeholder?: string;
   type?: 'text' | 'password';
 }) {
   return (
     <div className="flex flex-col gap-1">
       <label className="text-2xs font-mono uppercase tracking-wider text-text-dim">{label}</label>
       <input
         type={type}
         value={value}
         onChange={(e) => onChange(e.target.value)}
         placeholder={placeholder}
         className="ds-input"
       />
     </div>
   );
 }
 
 function Breadcrumb({
   prefix, bucket, onNavigate,
 }: { prefix: string; bucket: string; onNavigate: (p: string) => void }) {
   const parts = prefix.split('/').filter(Boolean);
   return (
     <div className="text-2xs font-mono text-text-muted flex items-center gap-1 flex-wrap">
       <button onClick={() => onNavigate('')} className="text-accent hover:underline">
         {bucket}/
       </button>
       {parts.map((p, i) => {
         const accum = parts.slice(0, i + 1).join('/') + '/';
         return (
           <button key={accum} onClick={() => onNavigate(accum)} className="text-accent hover:underline">
             {p}/
           </button>
         );
       })}
     </div>
   );
 }
 
 function EntryList({
   entries, checked, onToggle, onNavigate,
 }: {
   entries: ExternalObject[];
   checked: Set<string>;
   onToggle: (key: string, on: boolean) => void;
   onNavigate: (prefix: string) => void;
 }) {
   if (entries.length === 0) {
     return <div className="text-2xs text-text-dim text-center py-4">暂无对象</div>;
   }
   return (
     <div className="max-h-64 overflow-auto space-y-0.5">
       {entries.map((e) => (
         <div key={e.key} className="flex items-center gap-2 px-2 py-1 hover:bg-surface-hover text-xs">
           {e.isDir ? (
             <>
               <span className="w-3 inline-block" />
               <button
                 onClick={() => onNavigate(e.key)}
                 className="text-accent hover:underline font-mono flex-1 text-left truncate"
               >
                 📁 {e.name}
               </button>
             </>
           ) : (
             <>
               <input
                 type="checkbox"
                 checked={checked.has(e.key)}
                 onChange={(ev) => onToggle(e.key, ev.target.checked)}
                 className="accent-accent"
               />
               <span className="font-mono flex-1 truncate text-text">📄 {e.name}</span>
               <span className="text-2xs text-text-dim font-mono shrink-0">{formatBytes(e.size)}</span>
             </>
           )}
         </div>
       ))}
     </div>
   );
 }
 
 function HdfsEntryList({
   entries, checked, onToggle, onNavigate,
 }: {
   entries: HdfsEntry[];
   checked: Set<string>;
   onToggle: (key: string, on: boolean) => void;
   onNavigate: (name: string) => void;
 }) {
   if (entries.length === 0) {
     return <div className="text-2xs text-text-dim text-center py-4">暂无文件</div>;
   }
   return (
     <div className="max-h-64 overflow-auto space-y-0.5">
       {entries.map((e) => (
         <div key={e.key} className="flex items-center gap-2 px-2 py-1 hover:bg-surface-hover text-xs">
