               <span className="w-3 inline-block" />
               <button
                 onClick={() => onNavigate(e.key)}
                 className="text-accent hover:underline font-mono flex-1 text-left truncate"
               >
                 📁 {e.name}
               </button>
             </>
           ) : (
             <>
               <input
                 type="checkbox"
                 checked={checked.has(e.key)}
                 onChange={(ev) => onToggle(e.key, ev.target.checked)}
                 className="accent-accent"
               />
               <span className="font-mono flex-1 truncate text-text">📄 {e.name}</span>
               <span className="text-2xs text-text-dim font-mono shrink-0">{formatBytes(e.size)}</span>
             </>
           )}
         </div>
       ))}
     </div>
   );
 }
 
 function ImportProgressBar({ task }: { task: ImportTask }) {
   const pct = task.totalBytes > 0
     ? Math.min(100, Math.round((task.doneBytes / task.totalBytes) * 100))
     : 0;
   return (
     <div className="py-3">
       <div className="h-2 bg-line rounded-full overflow-hidden mb-2">
         <div className="h-full bg-accent transition-all duration-300" style={{ width: `${pct}%` }} />
       </div>
       <div className="text-2xs text-text-muted font-mono space-y-0.5">
         <div>
           {formatBytes(task.doneBytes)} / {formatBytes(task.totalBytes)} ({pct}%)
           {task.currentFile && ` — 当前: ${task.currentFile}`}
         </div>
         {task.status === 'RUNNING' && pct < 100 && (
           <div className="text-text-dim">速度: {formatSpeed(task.speed ?? 0)}</div>
         )}
         {task.status === 'DONE' && <div className="text-status-ok">✓ 导入完成</div>}
         {task.status === 'ERROR' && <div className="text-status-danger">✗ {task.errorMessage}</div>}
       </div>
     </div>
   );
 }
 
 // ─── 浏览面板 ─────────────────────────────────────────────────────
 
 function BrowsePanel({ reloadKey }: { reloadKey: number }) {
   const [bucket, setBucket] = useState('pictures');
   const [filter, setFilter] = useState('');
   const [records, setRecords] = useState<FileUploadRecord[]>([]);
   const [loading, setLoading] = useState(false);
 
   const load = useCallback(async () => {
     setLoading(true);
     try {
       // 文件浏览面板等同于"bucket 已有文件"视图：只展示已上传成功的；
       // 未完成（UPLOADING/PAUSED/FAILED）的占位记录由 UploadPanel 队列承载
       const page = await minioService.listRecords({ size: 200, status: 'SUCCESS' });
       setRecords(page.content);
     } catch {
       setRecords([]);
     } finally {
       setLoading(false);
     }
   }, []);
 
   // 监听 reloadKey 变化：UploadPanel 上传成功时由父组件递增此值，触发重新拉取
   useEffect(() => {
     load();
   }, [load, reloadKey]);
 
   const filtered = records.filter(
     (r) => (!bucket || r.bucket === bucket)
       && (!filter || r.fileName.toLowerCase().includes(filter.toLowerCase())),
   );
 
   const handlePreview = async (r: FileUploadRecord) => {
     try {
       const url = await minioService.previewUrl(r.fileId);
       window.open(url, '_blank');
     } catch (e) {
       toast.error(getErrorMessage(e, '生成预览链接失败'));
     }
   };
 
   const handleDelete = async (r: FileUploadRecord) => {
     if (!window.confirm(`确定删除 ${r.fileName} ?`)) return;
     try {
       await minioService.deleteRecord(r.fileId);
       load();
     } catch (e) {
       toast.error(getErrorMessage(e, '删除失败'));
     }
   };
 
   return (
     <Panel
       title={
         <span className="flex items-center gap-2">
           <Box className="w-4 h-4 text-accent" />
           文件浏览
         </span>
       }
       subtitle="当前用户上传的文件，按 Bucket 过滤"
       noPadding
     >
       <div className="p-4 flex flex-col gap-3 h-full overflow-auto">
         <div className="flex gap-2">
           <select
             value={bucket}
             onChange={(e) => setBucket(e.target.value)}
             className="ds-input flex-1"
           >
             {BUCKET_OPTIONS.map((b) => (
               <option key={b.value} value={b.value}>{b.label}</option>
             ))}
           </select>
           <input
             type="text"
             value={filter}
             onChange={(e) => setFilter(e.target.value)}
             placeholder="请输入文件名搜索"
             className="ds-input flex-1"
           />
           <Button onClick={load} disabled={loading}>
             {loading ? <Loader2 className="w-3 h-3 animate-spin" /> : '刷新'}
           </Button>
         </div>
 
         <div className="flex-1 min-h-0 overflow-auto">
           {filtered.length === 0 ? (
             <div className="text-center py-12 text-2xs text-text-dim">
               {bucket} — 暂无文件
             </div>
           ) : (
             <div className="space-y-1">
               {filtered.map((r) => {
                 const Icon = CATEGORY_ICON[r.fileType ?? 'UNCLASSIFIED'];
                 return (
                   <div
                     key={r.fileId}
                     className="flex items-center gap-2 px-2.5 py-2 border-0.5 border-line rounded-sm bg-bg-subtle/40 hover:bg-surface-hover transition-colors"
                   >
                     <Icon className="w-3.5 h-3.5 text-accent shrink-0" />
                     <div className="flex-1 min-w-0">
                       <div className="text-2xs text-text font-mono truncate" title={r.fileName}>
                         {r.fileName}
                       </div>
                       <div className="text-2xs text-text-dim">
                         {formatBytes(r.fileSize)} · {r.bucket}
                       </div>
                     </div>
                     <button
                       onClick={() => handlePreview(r)}
                       className="text-accent hover:text-accent-hover p-1"
                       title="预览"
                     >
                       <Eye className="w-3.5 h-3.5" />
                     </button>
                     <button
                       onClick={() => handleDelete(r)}
                       className="text-status-danger hover:opacity-70 p-1"
                       title="删除"
                     >
                       <Trash2 className="w-3.5 h-3.5" />
                     </button>
                   </div>
                 );
               })}
             </div>
           )}
         </div>
       </div>
     </Panel>
   );
 }
 
 // ─── 工具函数 ─────────────────────────────────────────────────────
 
 function sleep(ms: number) {
   return new Promise((r) => setTimeout(r, ms));
 }
 
 /** 通用任务进度轮询 */
 function pollTask(
   taskId: string,
   fetcher: (id: string) => Promise<ImportTask>,
   onUpdate: (t: ImportTask) => void,
   onDone: () => void,
 ) {
   const timer = setInterval(async () => {
     try {
       const t = await fetcher(taskId);
       onUpdate(t);
       if (t.status === 'DONE' || t.status === 'ERROR') {
         clearInterval(timer);
         setTimeout(onDone, 1500);
       }
     } catch {
       clearInterval(timer);
     }
   }, 500);
 }

