       )}
       <Button variant="ghost" size="sm" title="查看" onClick={onView}>
         <Eye className="w-3 h-3" />
       </Button>
       <Button
         variant="ghost"
         size="sm"
         disabled={!guard.canEdit}
         title={guard.editReason ?? '编辑'}
         onClick={guard.canEdit ? onEdit : undefined}
       >
         <Pencil className="w-3 h-3" />
       </Button>
       <Button
         variant="ghost"
         size="sm"
