 // ───────────────────────────────────────────────
 // 统一响应工具
 // ───────────────────────────────────────────────
 
 interface ApiResp<T> {
   code: number;
   msg?: string;
   message?: string;
   data: T;
 }
 
 interface PageData<T> {
   list?: T[];
   content?: T[];
   total?: number;
   totalElements?: number;
   page?: number;
   size?: number;
 }
 
 interface PageResult<T> {
   list: T[];
   total: number;
   page: number;
   size: number;
 }
 
 function unwrap<T>(resp: { data: ApiResp<T> }): T {
   const body = resp.data;
   if (body.code !== 200) {
     throw new Error(body.msg ?? body.message ?? `API ${body.code}`);
   }
   return body.data;
 }
 
 function unwrapPage<T>(resp: { data: ApiResp<PageData<T> | T[]> }): PageResult<T> {
   const data = unwrap(resp);
   if (Array.isArray(data)) {
     return { list: data, total: data.length, page: 0, size: data.length };
   }
   return {
     list: data.list ?? data.content ?? [],
     total: data.total ?? data.totalElements ?? 0,
     page: data.page ?? 0,
     size: data.size ?? (data.list ?? data.content ?? []).length,
   };
 }
 
