  * axios 不支持流，聊天 / AI 生成场景统一用此工具。
  */
 
 import { useAuthStore } from '@/store/useAuthStore';
 import { useSystemStore } from '@/store/useSystemStore';
 
 /** 原有工具：仅解析 data: 行，用于 agent/skill 等旧接口 */
 export async function* sseStream(
   url: string,
   body: unknown,
 ): AsyncIterable<Record<string, unknown>> {
   const resp = await fetch(url, {
     method: 'POST',
     headers: { 'Content-Type': 'application/json' },
     body: JSON.stringify(body),
   });
 
   if (!resp.ok) {
     throw new Error(`SSE 请求失败: ${resp.status}`);
   }
 
   const reader = resp.body!.getReader();
   const decoder = new TextDecoder();
   let buffer = '';
 
   while (true) {
     const { done, value } = await reader.read();
     if (done) break;
 
     buffer += decoder.decode(value, { stream: true });
     const lines = buffer.split('\n\n');
     buffer = lines.pop() ?? '';
 
     for (const block of lines) {
       const line = block.trim();
       if (!line.startsWith('data:')) continue;
       const raw = line.slice(5).trim();
       if (raw === '[DONE]') return;
       try {
         yield JSON.parse(raw);
       } catch {
         // 跳过无效行
       }
     }
   }
 }
 
 /** SSE 事件包：包含事件类型和 data 载荷 */
 export interface SseEvent {
   event: string;
   data: Record<string, unknown>;
 }
 
 /**
  * 升级版 SSE 读流：同时解析 event: 和 data: 两行，符合 SSE 标准协议。
  * 自动从 Zustand store 读取 Authorization 和 X-Tenant-Id 并注入请求头。
- * 用于本体 LLM 接口（/api/oms-ontology/chat）。
+ * 用于本体 LLM 接口（/api/ontology/chat）。
  */
 export async function* ontologySseStream(
   url: string,
   body: unknown,
 ): AsyncIterable<SseEvent> {
   const token = useAuthStore.getState().token ?? import.meta.env.VITE_API_TOKEN;
   const tenantId = useSystemStore.getState().selectedTenantId;
 
   const headers: Record<string, string> = {
     'Content-Type': 'application/json',
     'X-Tenant-Id': tenantId ?? '',
   };
   if (token) headers['Authorization'] = `Bearer ${token}`;
 
   const resp = await fetch(url, {
     method: 'POST',
     headers,
     body: JSON.stringify(body),
   });
 
   if (!resp.ok) {
     // 尝试解析 JSON 错误体
     let msg = `SSE 请求失败: ${resp.status}`;
     try {
       const err = await resp.json() as { message?: string };
       if (err.message) msg = err.message;
     } catch { /* ignore */ }
     throw new Error(msg);
   }
 
   const reader = resp.body!.getReader();
   const decoder = new TextDecoder();
   let buffer = '';
 
   while (true) {
     const { done, value } = await reader.read();
     if (done) break;
 
     buffer += decoder.decode(value, { stream: true });
 
     // SSE 标准：事件块以 \n\n 分隔
     const blocks = buffer.split('\n\n');
     buffer = blocks.pop() ?? '';
 
     for (const block of blocks) {
       if (!block.trim()) continue;
 
       let eventType = 'message';
       let dataLine = '';
 
       for (const line of block.split('\n')) {
         if (line.startsWith('event:')) {
           eventType = line.slice(6).trim();
         } else if (line.startsWith('data:')) {
           dataLine = line.slice(5).trim();
         }
       }
 
       if (!dataLine || dataLine === '[DONE]') {
         if (dataLine === '[DONE]') return;
         continue;
       }
 
       try {
         const data = JSON.parse(dataLine) as Record<string, unknown>;
         yield { event: eventType, data };
       } catch {
         // 跳过无效 JSON
       }
     }
   }
 }

